import os
import pandas as pd
from datetime import datetime

def task_func(excel_directory: str, file_name: str, column_name: str, start_date: str, end_date: str) -> pd.DataFrame:
    file_path = os.path.join(excel_directory, file_name)

    if not os.path.exists(file_path):
        raise FileNotFoundError(f"The file {file_path} does not exist.")

    try:
        df = pd.read_excel(file_path)
    except Exception as e:
        raise ValueError(f"Error reading the Excel file: {e}")

    if column_name not in df.columns:
        raise ValueError(f"The column '{column_name}' does not exist in the DataFrame.")

    try:
        start_date_parsed = datetime.strptime(start_date, "%Y-%m-%d")
        end_date_parsed = datetime.strptime(end_date, "%Y-%m-%d")
    except ValueError:
        raise ValueError("start_date and end_date must be in 'YYYY-MM-DD' format.")

    if df[column_name].dtype == 'object':
        df[column_name] = pd.to_datetime(df[column_name], errors='coerce')

    if df[column_name].isna().all():
        raise ValueError(f"All values in column '{column_name}' could not be converted to datetime.")

    filtered_df = df[(df[column_name] >= start_date_parsed) & (df[column_name] <= end_date_parsed)]

    return filtered_df

import subprocess
import psutil
import time
import os

def task_func(script_path: str, timeout=10) -> dict:
    if not os.path.exists(script_path):
        raise FileNotFoundError(f"Script not found: {script_path}")

    cpu_usage = 0.0
    memory_usage = 0.0
    start_time = time.time()

    try:
        process = subprocess.Popen([script_path], stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        proc = psutil.Process(process.pid)

        while True:
            if time.time() - start_time > timeout:
                if proc.is_running():
                    proc.terminate()
                    try:
                        proc.wait(timeout=5)
                    except psutil.TimeoutExpired:
                        proc.kill()
                break

            if not proc.is_running():
                break

            try:
                cpu_percent = proc.cpu_percent(interval=0.1)
                memory_info = proc.memory_info()
                memory_rss = memory_info.rss

                cpu_usage += cpu_percent
                memory_usage += memory_rss

            except (psutil.NoSuchProcess, psutil.AccessDenied):
                break

            time.sleep(0.1)

    except Exception as e:
        if process and process.poll() is None:
            process.terminate()
            try:
                process.wait(timeout=5)
            except subprocess.TimeoutExpired:
                process.kill()
        raise e

    return {
        'CPU Usage': cpu_usage,
        'Memory Usage': int(memory_usage)
    }

