        raise ET.ParseError(f"Failed to parse XML content: {e}")

    try:
        with open(output_csv_path, 'w', newline='', encoding='utf-8') as csvfile:
            if len(root) == 0:
                return

            # Extract field names from the first element
            fieldnames = root[0].keys()
            writer = csv.DictWriter(csvfile, fieldnames=fieldnames)
            writer.writeheader()

            # Write data rows
            for element in root:
                writer.writerow(element.attrib)
