import rsa
import urllib.request
from hashlib import sha256

def task_func(url):
    try:
        with urllib.request.urlopen(url) as response:
            if response.getcode() != 200:
                raise ValueError(f"HTTP error: {response.getcode()}")
            content = response.read()
    except (urllib.error.URLError, ValueError) as e:
        if isinstance(e, urllib.error.URLError):
            raise e
        else:
            raise ValueError(f"Error reaching server: {e}")

    try:
        hash_object = sha256(content)
        hash_digest = hash_object.digest()
        private_key, public_key = rsa.newkeys(2048)
        signed_hash = rsa.sign(hash_digest, private_key, 'SHA-256')
        signed_hex = signed_hash.hex()
        return public_key, signed_hex, hash_digest
    except rsa.pkcs1.VerificationError as e:
        raise rsa.pkcs1.VerificationError(f"Failed to sign hash: {e}")

