import shutil
import pathlib

def task_func(source_path, destination_path):
    source = pathlib.Path(source_path)
    destination = pathlib.Path(destination_path)

    if not source.exists() or not source.is_dir():
        raise ValueError("source_path does not exist or is not a directory")

    if not destination.exists():
        destination.mkdir(parents=True, exist_ok=True)

    copied_files = []
    for item in source.iterdir():
        if item.is_file():
            shutil.copy2(item, destination)
            copied_files.append(item.name)

    return (source.name, copied_files)

import itertools
import math
from pandas import Series

def task_func(elements, subset_size, top_n=2):
    if subset_size > len(elements):
        return 1, Series([])
    if subset_size == 0:
        return 1, Series([])

    subsets = itertools.combinations(elements, subset_size)
    sums = [sum(subset) for subset in subsets]
    product_of_sums = math.prod(sums)

    top_n_sums = sorted(sums, reverse=True)[:top_n]
    return product_of_sums, Series(top_n_sums)

