import os
import re
import hashlib

def task_func(path, delimiter):
    components = re.split(f'({re.escape(delimiter)})', path)
    result = []

    # Reconstruct the path with delimiters preserved
    current_path = ""
    for i, component in enumerate(components):
        if component == delimiter:
            current_path += delimiter
        else:
            current_path += component
            # Check if current_path is a file
            if os.path.isfile(current_path):
                # Compute hash of the file
                hash_obj = hashlib.md5()
                try:
                    with open(current_path, 'rb') as f:
                        for chunk in iter(lambda: f.read(4096), b""):
                            hash_obj.update(chunk)
                    file_hash = hash_obj.hexdigest()
                except (IOError, OSError):
                    file_hash = None
            else:
                file_hash = None
            result.append((component, file_hash))

    return result

