from sklearn.preprocessing import LabelEncoder

def task_func(df, dct, columns=None):
    if not isinstance(df, pd.DataFrame):
        raise ValueError("Input df must be a DataFrame")

    df_processed = df.copy()

    # Replace specified values
    if dct:
        df_processed = df_processed.replace(dct)

    # Identify categorical and numerical columns
    if columns is None:
        columns = df_processed.columns

    categorical_cols = df_processed[columns].select_dtypes(include=['object', 'category']).columns
    numerical_cols = df_processed[columns].select_dtypes(include=['int64', 'float64']).columns

    # Encode categorical columns
    for col in categorical_cols:
        if col in columns:
            le = LabelEncoder()
            df_processed[col] = le.fit_transform(df_processed[col].astype(str))

    # Standardize numerical columns
    for col in numerical_cols:
        if col in columns:
            mean_val = df_processed[col].mean()
            std_val = df_processed[col].std()
            if std_val != 0:
                df_processed[col] = (df_processed[col] - mean_val) / std_val
            else:
                df_processed[col] = 0  # If std is 0, set to 0 to avoid division by zero

    return df_processed

