    # Search for all JSON files recursively in the directory and subdirectories
    json_files = glob(os.path.join(directory, "**", "*.json"), recursive=True)

    for file_path in json_files:
        try:
            with open(file_path, 'r', encoding='utf-8') as file:
                data = json.load(file)

                # Check if the string exists in the JSON data structure
                if isinstance(data, dict):
                    if _search_in_dict(data, string):
                        result.append(file_path)
                elif isinstance(data, list):
                    if _search_in_list(data, string):
                        result.append(file_path)
                elif isinstance(data, str):
                    if data == string:
