import subprocess
import time
import json
import platform
LOGFILE_PATH = "logfile.log"
def task_func(interval, duration):
    if interval <= 0 or duration <= 0:
        raise ValueError("Both interval and duration must be greater than zero.")

    log_data = []
    start_time = time.time()

    while (time.time() - start_time) < duration:
        try:
            if platform.system() == "Windows":
                # Use wmic to get CPU usage on Windows
                result = subprocess.run(['wmic', 'cpu', 'get', 'loadpercentage'], 
                                      capture_output=True, text=True, check=False)
                cpu_usage = result.stdout.strip().split('\n')
                # Extract the numeric value from the output
                for line in cpu_usage:
                    if line.strip().isdigit():
                        cpu_usage = int(line.strip())
                        break
                else:
                    cpu_usage = 0
            else:
                # Use top command on Unix/Linux systems
                result = subprocess.run(['top', '-bn1'], capture_output=True, text=True, check=False)
                # Parse the line containing CPU usage
                for line in result.stdout.split('\n'):
                    if 'Cpu(s)' in line:
                        # Extract the percentage value (e.g., 12.3%)
                        parts = line.split(',')
                        cpu_usage_str = parts[0].strip().split()[1]
                        cpu_usage = float(cpu_usage_str.rstrip('%'))
                        break
                else:
                    cpu_usage = 0
        except Exception:
            cpu_usage = 0

        timestamp = time.time()
        log_data.append({
            "timestamp": timestamp,
            "cpu_usage": cpu_usage
        })

        # Wait for the next interval, but avoid accumulating too much delay
        elapsed = time.time() - start_time
        if elapsed < duration:
            time.sleep(max(0, interval - (time.time() - start_time + elapsed)))

    try:
        with open(LOGFILE_PATH, 'w') as f:
            json.dump(log_data, f, indent=2)
        return LOGFILE_PATH
    except IOError:
        return None

