def task_func(path, delimiter="/"):
    if not isinstance(path, str):
        raise ValueError("Path must be a string")
    if not path:
        raise ValueError("Path cannot be empty")
    if delimiter not in path:
        raise ValueError("Path must contain the delimiter")

    components = path.split(delimiter)
    if not all(components):
        raise ValueError("Path contains invalid components (empty segments)")

    result = []
    current_path = ""

    for component in components:
        if not component:
            continue
        current_path = os.path.join(current_path, component) if current_path else component

        if not os.path.exists(current_path):
            raise FileNotFoundError(f"Path does not exist: {current_path}")

        if not os.path.isdir(current_path):
            raise ValueError(f"Path is not a directory: {current_path}")

        try:
            stat = shutil.disk_usage(current_path)
            usage = {
                'total': stat.total,
                'used': stat.used,
                'free': stat.free
            }
            result.append((component, usage))
        except Exception as e:
            raise ValueError(f"Could not get disk usage for {current_path}: {e}")

    return result

