def task_func(target_value='332', csv_dir='./csv_files/', processed_dir='./processed_files/', simulate=False):
    result = {}

    # Ensure processed directory exists
    if not os.path.exists(processed_dir):
        os.makedirs(processed_dir)

    # Scan the directory for CSV files
    for filename in os.listdir(csv_dir):
        if filename.lower().endswith('.csv'):
            file_path = os.path.join(csv_dir, filename)
            found_index = None

            # Read the CSV file and find the row with the target value in the first cell
            with open(file_path, 'r', newline='', encoding='utf-8') as csvfile:
                reader = csv.reader(csvfile)
                for index, row in enumerate(reader):
                    if row and row[0] == target_value:
                        found_index = index
                        break

            # Store the result
            if found_index is not None:
                result[filename] = found_index

            # Move file if not in simulation mode
            if not simulate and found_index is not None:
                shutil.move(file_path, os.path.join(processed_dir, filename))

    return result

