import hashlib
import os

def task_func(file_path1, file_path2):
    if not os.path.exists(file_path1):
        raise FileNotFoundError(f"File not found: {file_path1}")
    if not os.path.exists(file_path2):
        raise FileNotFoundError(f"File not found: {file_path2}")

    def get_md5(file_path):
        hash_md5 = hashlib.md5()
        with open(file_path, "rb") as f:
            # Read the file in chunks to handle large files efficiently
            for chunk in iter(lambda: f.read(4096), b""):
                hash_md5.update(chunk)
        return hash_md5.hexdigest()

    hash1 = get_md5(file_path1)
    hash2 = get_md5(file_path2)

    return hash1 == hash2

import subprocess
import psutil
import time
import os

def task_func(script_path: str, timeout=10) -> dict:
    if not os.path.exists(script_path):
        raise FileNotFoundError(f"Script not found: {script_path}")

    cpu_usage = 0.0
    memory_usage = 0.0
    start_time = time.time()

    try:
        process = subprocess.Popen([script_path], stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        proc = psutil.Process(process.pid)

        while True:
            if time.time() - start_time > timeout:
                if proc.is_running():
                    proc.terminate()
                    try:
                        proc.wait(timeout=5)
                    except psutil.TimeoutExpired:
                        proc.kill()
                break

            if not proc.is_running():
                break

            try:
                cpu_percent = proc.cpu_percent(interval=0.1)
                memory_info = proc.memory_info()
                memory_rss = memory_info.rss

                cpu_usage += cpu_percent
                memory_usage += memory_rss

            except (psutil.NoSuchProcess, psutil.AccessDenied):
                break

