from pathlib import Path

def task_func(dir_path: str, predicates: list) -> dict:
    if not predicates:
        raise ValueError("If no valid predicates are provided.")

    path = Path(dir_path)
    if not path.exists():
        raise FileNotFoundError(f"The specified directory does not exist: {dir_path}")
    if not path.is_dir():
        raise FileNotFoundError(f"The specified path is not a directory: {dir_path}")

    # Deduplicate predicates
    unique_predicates = []
    seen = set()
    for pred in predicates:
        if pred not in seen:
            unique_predicates.append(pred)
            seen.add(pred)

    result = {}
    try:
        for item in path.iterdir():
            item_name = item.name
            item_results = []
            for pred in unique_predicates:
                if isinstance(pred, str):
                    if re.match(pred, item_name):
                        item_results.append(True)
                    else:
                        item_results.append(False)
                elif callable(pred):
                    try:
                        if pred(item_name):
                            item_results.append(True)
                        else:
                            item_results.append(False)
                    except Exception:
                        item_results.append(False)
                else:
                    item_results.append(False)
            result[item_name] = item_results
    except Exception as e:
        raise e

    return result

