import itertools
import math
from pandas import Series

def task_func(elements, subset_size, top_n=2):
    if subset_size > len(elements):
        return 1, Series([])
    if subset_size == 0:
        return 1, Series([])

    subsets = itertools.combinations(elements, subset_size)
    sums = [sum(subset) for subset in subsets]
    product_of_sums = math.prod(sums)

    top_n_sums = sorted(sums, reverse=True)[:top_n]
    return product_of_sums, Series(top_n_sums)

import re
import pandas as pd

def task_func(df: pd.DataFrame, column_name: str, pattern: str) -> pd.DataFrame:
    if not pattern:
        return df.copy()

    def reverse_matching_words(text):
        words = text.split()
        matching_words = []
        non_matching_words = []

        for word in words:
            if re.search(pattern, word):
                matching_words.append(word)
            else:
                non_matching_words.append(word)

        # Reverse the order of matching words while keeping non-matching in original order
        matching_words.reverse()

        # Combine the lists back together
        result_words = []
        matching_idx = 0
        non_matching_idx = 0

        for word in words:
            if re.search(pattern, word):
                result_words.append(matching_words[matching_idx])
                matching_idx += 1
            else:
                result_words.append(non_matching_words[non_matching_idx])
                non_matching_idx += 1

        return ' '.join(result_words)

    # Create a copy of the DataFrame
    result_df = df.copy()

    # Apply the function to the specified column
    result_df[column_name] = result_df[column_name].astype(str).apply(reverse_matching_words)

    return result_df

