def task_func(dictionary, item, sample_size=None, random_seed=None):
    # Convert dictionary to DataFrame
    df = pd.DataFrame.from_dict(dictionary, orient='index')

    # Find positions where the item is found
    positions = []
    for row_idx in range(df.shape[0]):
        for col_idx in range(df.shape[1]):
            if df.iloc[row_idx, col_idx] == item:
                positions.append((row_idx, col_idx))

    # Calculate frequency distribution
    frequency = len(positions)

    # Optionally return a random sample of positions
    if sample_size is not None and random_seed is not None:
        seed(random_seed)
        sample_positions = []
        for _ in range(min(sample_size, frequency)):
            if positions:
                random_idx = randint(0, len(positions) - 1)
                sample_positions.append(positions.pop(random_idx))
        positions = sample_positions

    return positions, df

