import requests
import logging

def task_func(repo_url: str) -> dict:
    logging.basicConfig(level=logging.INFO)

    try:
        response = requests.get(repo_url)
        response.raise_for_status()

        repo_data = response.json()

        # Check for a large number of open issues
        open_issues_count = repo_data.get('open_issues_count', 0)
        if open_issues_count > 100:
            logging.warning(f"Repository has a high number of open issues: {open_issues_count}")

        return repo_data

    except requests.exceptions.HTTPError as e:
        if response.status_code == 403 and 'rate limit' in str(e).lower():
            raise requests.exceptions.HTTPError("GitHub API rate limit exceeded") from e
        raise requests.exceptions.HTTPError(f"HTTP error occurred: {e}") from e
    except requests.exceptions.RequestException as e:
        raise requests.exceptions.RequestException(f"Request failed: {e}") from e

import json
import pandas as pd
import numpy as np
from collections import defaultdict

def task_func(input_file="data.json"):
    with open(input_file, 'r') as f:
        data = json.load(f)

    # Collect numeric values for each key
    values_by_key = defaultdict(list)

    for item in data:
        for key, value in item.items():
            if isinstance(value, (int, float)) and not pd.isna(value):
                values_by_key[key].append(value)

    # Calculate mean and median for each key
    results = {}
    for key, values in values_by_key.items():
        mean_val = np.mean(values)
        median_val = np.median(values)
        results[key] = {'mean': mean_val, 'median': median_val}

    # Create DataFrame and sort by key
    df = pd.DataFrame.from_dict(results, orient='index')
    df = df.sort_index()

    return df

import re
import socket

def task_func(ip_addresses: list) -> dict:
    result = {}
    for ip in ip_addresses:
        # Validate IP address format
        if re.match(r'^(\d{1,3}\.){3}\d{1,3}$', ip):
            try:
                hostname = socket.gethostbyaddr(ip)[0]
                result[ip] = hostname
            except socket.herror:
                result[ip] = None
        else:
            result[ip] = None
    return result

import json
import requests
import chardet

# Constants
API_URL = "http://api.example.com/data"

def task_func(url=API_URL, from_encoding=None, to_encoding="utf8"):
    response = requests.get(url, timeout=5)
    content = response.content

    if not content:
        return {}

    if from_encoding is None:
        detected = chardet.detect(content)
        if detected['encoding'] is None:
            raise ValueError("Unable to detect encoding for non-empty content")
        from_encoding = detected['encoding']

    try:
        decoded_content = content.decode(from_encoding)
        encoded_content = decoded_content.encode(to_encoding)
        json_data = json.loads(encoded_content.decode(to_encoding))
        return json_data
    except (json.JSONDecodeError, UnicodeDecodeError, UnicodeEncodeError) as e:
        raise ValueError(f"Failed to parse JSON after encoding conversion: {e}")

import binascii
import hashlib

def task_func(input_string, verify_hash=None):
    if not isinstance(input_string, str):
        raise TypeError("Input must be a string")
    if verify_hash is not None and not isinstance(verify_hash, str):
        raise TypeError("verify_hash must be a string or None")

    sha256_hash = hashlib.sha256(input_string.encode('utf-8')).hexdigest()

    if verify_hash is not None:
        return sha256_hash, sha256_hash == verify_hash
    else:
        return sha256_hash

import json
import numpy as np
import matplotlib.pyplot as plt
import seaborn as sns
import pandas as pd

def task_func(json_data: str, key_path: list):
    try:
        data = json.loads(json_data)
    except json.JSONDecodeError:
        raise ValueError("The data string is empty or corrupted.")

    current = data
    for key in key_path:
        if isinstance(current, dict) and key in current:
            current = current[key]
        else:
            raise KeyError(f"Key '{key}' not found in the path.")

    if isinstance(current, list):
        numeric_data = []
        for item in current:
            try:
                numeric_data.append(float(item))
            except (ValueError, TypeError):
                continue
    elif isinstance(current, (int, float)):
        numeric_data = [float(current)]
    else:
        raise ValueError("No numeric data found in the specified path.")

    if not numeric_data:
        raise ValueError("No numeric data found, or the data string is empty or corrupted.")

    fig, ax = plt.subplots(figsize=(8, 6))
    sns.boxplot(x=numeric_data, ax=ax)
    ax.set_title('Boxplot of Extracted Numerical Data')
    ax.set_xlabel('Values')

    return fig

import json
from datetime import datetime
from decimal import Decimal

def task_func(my_obj):
    def json_serializer(obj):
        if isinstance(obj, datetime):
            return obj.isoformat()
        if isinstance(obj, Decimal):
            return float(obj)
        raise TypeError(f"Object of type {type(obj)} is not JSON serializable")

    return json.dumps(my_obj, default=json_serializer)

import pandas as pd
from statistics import mean

def task_func(df: pd.DataFrame) -> dict:
    if 'Name' not in df.columns or 'Score' not in df.columns:
        raise ValueError("If the DataFrame does not have the 'Name' and 'Score' columns.")

