import numpy as np
import pandas as pd
# Constants
RANGE = (1, 100)
def task_func(L):
    # Calculate dimensions by multiplying pairs from nested lists
    rows = 1
    cols = 1
    for sublist in L:
        for i in range(len(sublist)):
            if i % 2 == 0:
                rows *= sublist[i]
            else:
                cols *= sublist[i]

    # Generate random integers within the specified range
    data = np.random.randint(RANGE[0], RANGE[1] + 1, size=(rows, cols))

    # Create and return DataFrame
    return pd.DataFrame(data)

